create table if not exists versiculos_dia (
  id                bigint generated always as identity primary key,
  fecha             date    not null unique,
  dia_semana        text    not null,
  tema              text    not null,
  cita              text    not null,
  libro             text    not null,
  capitulo          int     not null,
  versiculo_inicio  int     not null,
  versiculo_fin     int,
  texto             text,
  semestre          text    not null default '2026-1'
);

insert into versiculos_dia
  (fecha, dia_semana, tema, cita, libro, capitulo, versiculo_inicio, versiculo_fin, texto)
values
-- ===================== ENERO 2026 =====================
('2026-01-01','Jueves','La preparación para su regreso','1 Tesalonicenses 5:23','1 Tesalonicenses',5,23,NULL,'Y el Dios de paz os santifique en todo; para que vuestro espíritu y alma y cuerpo sea guardado entero sin reprensión para la venida de nuestro Señor Jesucristo.'),
('2026-01-02','Viernes','La preparación para su regreso','1 Juan 2:28','1 Juan',2,28,NULL,'Y ahora, hijitos, perseverad en él; para que cuando apareciere, tengamos confianza, y no seamos confundidos de él en su venida.'),
('2026-01-03','Sábado','La preparación para su regreso','Apocalipsis 14:12','Apocalipsis',14,12,NULL,'Aquí está la paciencia de los santos; aquí están los que guardan los mandamientos de Dios, y la fe de Jesús.'),
('2026-01-04','Domingo','Consejos a los hombres cristianos','Job 11:11','Job',11,11,NULL,'Porque él conoce á los hombres vanos: ve asimismo la iniquidad, ¿y no hará caso?'),
('2026-01-05','Lunes','Consejos a los hombres cristianos','Salmos 36:7','Salmos',36,7,NULL,'¡Cuán ilustre, oh Dios, es tu misericordia! Por eso los hijos de los hombres se amparan bajo la sombra de tus alas.'),
('2026-01-06','Martes','Consejos a los hombres cristianos','Salmos 58:1','Salmos',58,1,NULL,'Oh congregación, ¿pronunciáis en verdad justicia? ¿juzgáis rectamente, hijos de los hombres?'),
('2026-01-07','Miércoles','Consejos a los hombres cristianos','Salmos 90:3','Salmos',90,3,NULL,'Vuelves al hombre hasta ser quebrantado, y dices: Convertíos, hijos de los hombres.'),
('2026-01-08','Jueves','Consejos a los hombres cristianos','Salmos 24:1','Salmos',24,1,NULL,'De Jehová es la tierra y su plenitud; el mundo, y los que en él habitan.'),
('2026-01-09','Viernes','Consejos a los hombres cristianos','Proverbios 29:10','Proverbios',29,10,NULL,'Los hombres sanguinarios aborrecen al perfecto: mas los rectos buscan su contentamiento.'),
('2026-01-10','Sábado','Consejos a los hombres cristianos','Mateo 5:16','Mateo',5,16,NULL,'Así alumbre vuestra luz delante de los hombres, para que vean vuestras obras buenas, y glorifiquen á vuestro Padre que está en los cielos.'),
('2026-01-11','Domingo','Consejos a los hombres cristianos','1 Corintios 7:3','1 Corintios',7,3,NULL,'El marido pague á la mujer la debida benevolencia; y asimismo la mujer al marido.'),
('2026-01-12','Lunes','Consejos a los hombres cristianos','1 Corintios 7:27','1 Corintios',7,27,NULL,'¿Estás ligado á mujer? no procures soltarte. ¿Estás suelto de mujer? no procures mujer.'),
('2026-01-13','Martes','Consejos a los hombres cristianos','Efesios 5:23','Efesios',5,23,NULL,'Porque el marido es cabeza de la mujer, así como Cristo es cabeza de la iglesia; y él es el que da la salud al cuerpo.'),
('2026-01-14','Miércoles','Consejos a los hombres cristianos','Efesios 5:25','Efesios',5,25,NULL,'Maridos, amad á vuestras mujeres, así como Cristo amó á la iglesia, y se entregó á sí mismo por ella,'),
('2026-01-15','Jueves','Consejos a los hombres cristianos','Efesios 5:28','Efesios',5,28,NULL,'Así también los maridos deben amar á sus mujeres como á sus mismos cuerpos. El que ama á su mujer, á sí mismo se ama.'),
('2026-01-16','Viernes','Consejos a los hombres cristianos','Colosenses 3:19','Colosenses',3,19,NULL,'Maridos, amad á vuestras mujeres, y no seáis desapacibles con ellas.'),
('2026-01-17','Sábado','Consejos a los hombres cristianos','1 Pedro 3:7','1 Pedro',3,7,NULL,'Vosotros maridos, semejantemente, habitad con ellas según ciencia, dando honor á la mujer como á vaso más frágil, y como á herederas juntamente de la gracia de la vida; para que vuestras oraciones no sean impedidas.'),
('2026-01-18','Domingo','Consejos a las mujeres cristianas','Deuteronomio 22:5','Deuteronomio',22,5,NULL,'No vestirá la mujer hábito de hombre, ni el hombre vestirá ropa de mujer; porque abominación es á Jehová tu Dios cualquiera que esto hace.'),
('2026-01-19','Lunes','Consejos a las mujeres cristianas','Proverbios 12:4','Proverbios',12,4,NULL,'La mujer virtuosa corona es de su marido: mas la mala, como carcoma en sus huesos.'),
('2026-01-20','Martes','Consejos a las mujeres cristianas','Proverbios 14:1','Proverbios',14,1,NULL,'La mujer sabia edifica su casa: mas la necia con sus manos la derriba.'),
('2026-01-21','Miércoles','Consejos a las mujeres cristianas','Proverbios 31:30','Proverbios',31,30,NULL,'Engañosa es la gracia, y vana la hermosura: la mujer que teme á Jehová, ésa será alabada.'),
('2026-01-22','Jueves','Consejos a las mujeres cristianas','1 Corintios 11:3','1 Corintios',11,3,NULL,'Mas quiero que sepáis, que Cristo es la cabeza de todo varón; y el varón es la cabeza de la mujer; y Dios la cabeza de Cristo.'),
('2026-01-23','Viernes','Consejos a las mujeres cristianas','1 Corintios 11:5','1 Corintios',11,5,NULL,'Mas toda mujer que ora ó profetiza no cubierta su cabeza, afrenta su cabeza; porque lo mismo es que si se rayese.'),
('2026-01-24','Sábado','Consejos a las mujeres cristianas','1 Corintios 11:6','1 Corintios',11,6,NULL,'Porque si la mujer no se cubre, trasquílese también: y si es deshonesto á la mujer trasquilarse ó raerse, cúbrase.'),
('2026-01-25','Domingo','Consejos a las mujeres cristianas','1 Corintios 11:10','1 Corintios',11,10,NULL,'Por lo cual, la mujer debe tener señal de potestad sobre su cabeza, por causa de los ángeles.'),
('2026-01-26','Lunes','Consejos a las mujeres cristianas','1 Corintios 11:13','1 Corintios',11,13,NULL,'Juzgad vosotros mismos: ¿es honesto orar la mujer á Dios no cubierta?'),
('2026-01-27','Martes','Consejos a las mujeres cristianas','1 Timoteo 2:9','1 Timoteo',2,9,NULL,'Asimismo también las mujeres, ataviándose en hábito honesto, con vergüenza y modestia; no con cabellos encrespados, ú oro, ó perlas, ó vestidos costosos,'),
('2026-01-28','Miércoles','Consejos a las mujeres cristianas','1 Timoteo 2:10','1 Timoteo',2,10,NULL,'Sino de buenas obras, como conviene á mujeres que profesan piedad.'),
('2026-01-29','Jueves','Consejos a las mujeres cristianas','1 Timoteo 2:12','1 Timoteo',2,12,NULL,'Porque no permito á la mujer enseñar, ni tomar autoridad sobre el hombre, sino estar en silencio.'),
('2026-01-30','Viernes','Consejos a las mujeres cristianas','Tito 2:3','Tito',2,3,NULL,'Las viejas, asimismo, se distingan en un porte santo; no calumniadoras, no dadas á mucho vino, maestras de honestidad:'),
('2026-01-31','Sábado','Consejos a las mujeres cristianas','Tito 2:4','Tito',2,4,NULL,'Que enseñen á las mujeres jóvenes á ser prudentes, á que amen á sus maridos, á que amen á sus hijos,'),
-- ===================== FEBRERO 2026 =====================
('2026-02-01','Domingo','Consejos a las mujeres cristianas','Tito 2:5','Tito',2,5,NULL,'A ser templadas, castas, que tengan cuidado de la casa, buenas, sujetas á sus maridos; porque la palabra de Dios no sea blasfemada.'),
('2026-02-02','Lunes','Consejos a las mujeres cristianas','1 Corintios 14:34','1 Corintios',14,34,NULL,'Vuestras mujeres callen en las congregaciones; porque no les es permitido hablar, sino que estén sujetas, como también la ley dice.'),
('2026-02-03','Martes','Consejos a las mujeres cristianas','Proverbios 31:20','Proverbios',31,20,NULL,'Alargó su mano al pobre, y extendió sus manos al menesteroso.'),
('2026-02-04','Miércoles','Consejos a los jóvenes cristianos','Eclesiastés 11:10','Eclesiastés',11,10,NULL,'Quita pues el enojo de tu corazón, y aparta el mal de tu carne: porque la mocedad y la juventud son vanidad.'),
('2026-02-05','Jueves','Consejos a los jóvenes cristianos','Isaías 40:30','Isaías',40,30,NULL,'Los mancebos se fatigan y se cansan, los mozos flaquean y caen:'),
('2026-02-06','Viernes','Consejos a los jóvenes cristianos','Isaías 40:31','Isaías',40,31,NULL,'Mas los que esperan á Jehová tendrán nuevas fuerzas; levantarán las alas como águilas; correrán, y no se cansarán; caminarán, y no se fatigarán.'),
('2026-02-07','Sábado','Consejos a los jóvenes cristianos','1 Pedro 5:5','1 Pedro',5,5,NULL,'Igualmente, mancebos, sed sujetos á los ancianos; y todos sumisos unos á otros, revestíos de humildad; porque Dios resiste á los soberbios, y da gracia á los humildes.'),
('2026-02-08','Domingo','Consejos a las señoritas cristianas','Deuteronomio 22:5','Deuteronomio',22,5,NULL,'No vestirá la mujer hábito de hombre, ni el hombre vestirá ropa de mujer; porque abominación es á Jehová tu Dios cualquiera que esto hace.'),
('2026-02-09','Lunes','Consejos a las señoritas cristianas','Eclesiastés 12:1','Eclesiastés',12,1,NULL,'Y acuérdate de tu Criador en los días de tu juventud, antes que vengan los malos días, y lleguen los años, de los cuales digas, No tengo en ellos contentamiento;'),
('2026-02-10','Martes','Consejos a las señoritas cristianas','Romanos 13:14','Romanos',13,14,NULL,'Mas vestíos del Señor Jesucristo, y no hagáis caso de la carne en sus deseos.'),
('2026-02-11','Miércoles','Consejos a las señoritas cristianas','2 Corintios 8:21','2 Corintios',8,21,NULL,'Procurando las cosas honestas, no sólo delante del Señor, mas aun delante de los hombres.'),
('2026-02-12','Jueves','Consejos a las señoritas cristianas','1 Timoteo 3:11','1 Timoteo',3,11,NULL,'Las mujeres asimismo, honestas, no detractoras, templadas, fieles en todo.'),
('2026-02-13','Viernes','Consejos a las señoritas cristianas','1 Timoteo 5:14','1 Timoteo',5,14,NULL,'Quiero pues, que las que son jóvenes se casen, críen hijos, gobiernen la casa; que ninguna ocasión den al adversario para maldecir.'),
('2026-02-14','Sábado','Consejos a las señoritas cristianas','1 Timoteo 5:15','1 Timoteo',5,15,NULL,'Porque ya algunas han vuelto atrás en pos de Satanás.'),
('2026-02-15','Domingo','La ley de Dios o moral','Deuteronomio 4:12','Deuteronomio',4,12,NULL,'Y habló Jehová con vosotros de en medio del fuego: oisteis la voz de sus palabras, mas á excepción de oir la voz, ninguna figura visteis:'),
('2026-02-16','Lunes','La ley de Dios o moral','Éxodo 31:18','Éxodo',31,18,NULL,'Y dió á Moisés, como acabó de hablar con él en el monte de Sinaí, dos tablas del testimonio, tablas de piedra escritas con el dedo de Dios.'),
('2026-02-17','Martes','La ley de Dios o moral','Éxodo 23:12','Éxodo',23,12,NULL,'Seis días harás tus negocios, y al séptimo día holgarás, á fin que descanse tu buey y tu asno, y tome refrigerio el hijo de tu sierva, y el extranjero.'),
('2026-02-18','Miércoles','La ley de Dios o moral','Salmos 19:7','Salmos',19,7,NULL,'La ley de Jehová es perfecta, que vuelve el alma: el testimonio de Jehová, fiel, que hace sabio al pequeño.'),
('2026-02-19','Jueves','La ley de Dios o moral','Mateo 5:17-18','Mateo',5,17,18,'No penséis que he venido para abrogar la ley ó los profetas: no he venido para abrogar, sino á cumplir. Porque de cierto os digo, que hasta que perezca el cielo y la tierra, ni una jota ni un tilde perecerá de la ley, hasta que todas las cosas sean hechas.'),
('2026-02-20','Viernes','La ley de Dios o moral','Santiago 2:12','Santiago',2,12,NULL,'Así hablad, y así obrad, como los que habéis de ser juzgados por la ley de libertad.'),
('2026-02-21','Sábado','La ley de Dios o moral','Romanos 7:14','Romanos',7,14,NULL,'Porque sabemos que la ley es espiritual; mas yo soy carnal, vendido á sujeción del pecado.'),
('2026-02-22','Domingo','La ley de Dios o moral','Romanos 3:27','Romanos',3,27,NULL,'¿Dónde pues está la jactancia? Es excluída. ¿Por cuál ley? ¿de las obras? No; mas por la ley de la fe.'),
('2026-02-23','Lunes','La ley de Dios o moral','Romanos 7:12','Romanos',7,12,NULL,'De manera que la ley á la verdad es santa, y el mandamiento santo, y justo, y bueno.'),
('2026-02-24','Martes','La ley de Dios o moral','Deuteronomio 5:22','Deuteronomio',5,22,NULL,'Estas palabras habló Jehová á toda vuestra congregación en el monte, de en medio del fuego, de la nube y de la oscuridad, á gran voz: y no añadió más. Y escribiólas en dos tablas de piedra, las cuales me dió á mí.'),
('2026-02-25','Miércoles','La ley de Dios o moral','Éxodo 25:21','Éxodo',25,21,NULL,'Y pondrás la cubierta encima del arca, y en el arca pondrás el testimonio que yo te daré.'),
('2026-02-26','Jueves','La ley de Dios o moral','1 Reyes 8:9','1 Reyes',8,9,NULL,'En el arca ninguna cosa había más de las dos tablas de piedra que había allí puesto Moisés en Horeb, donde Jehová hizo la alianza con los hijos de Israel, cuando salieron de la tierra de Egipto.'),
('2026-02-27','Viernes','La ley de Dios o moral','Éxodo 20:3-5','Éxodo',20,3,5,'No tendrás dioses ajenos delante de mí. No te harás imagen, ni ninguna semejanza de cosa que esté arriba en el cielo, ni abajo en la tierra, ni en las aguas debajo de la tierra: No te inclinarás á ellas, ni las honrarás; porque yo soy Jehová tu Dios, fuerte, celoso, que visito la maldad de los padres sobre los hijos, sobre los terceros y sobre los cuartos, á los que me aborrecen,'),
('2026-02-28','Sábado','La ley de Dios o moral','Éxodo 20:6-10','Éxodo',20,6,10,'Y que hago misericordia en millares á los que me aman, y guardan mis mandamientos. No tomarás el nombre de Jehová tu Dios en vano; porque no dará por inocente Jehová al que tomare su nombre en vano. Acordarte has del día del reposo, para santificarlo: Seis días trabajarás, y harás toda tu obra; Mas el séptimo día será reposo para Jehová tu Dios: no hagas en él obra alguna, tú, ni tu hijo, ni tu hija, ni tu siervo, ni tu criada ni tu bestia, ni tu extranjero que está dentro de tus puertas:'),
-- ===================== MARZO 2026 =====================
('2026-03-01','Domingo','La ley de Moisés o ceremonial','Deuteronomio 1:6','Deuteronomio',1,6,NULL,'Jehová nuestro Dios nos habló en Horeb, diciendo: Harto habéis estado en este monte;'),
('2026-03-02','Lunes','La ley de Moisés o ceremonial','Deuteronomio 31:24','Deuteronomio',31,24,NULL,'Y como acabó Moisés de escribir las palabras de esta ley en un libro hasta concluirse,'),
('2026-03-03','Martes','La ley de Moisés o ceremonial','Deuteronomio 31:25-26','Deuteronomio',31,25,26,'Mandó Moisés á los Levitas que llevaban el arca del pacto de Jehová, diciendo: Tomad este libro de la ley, y ponedlo al lado del arca del pacto de Jehová vuestro Dios, y esté allí por testigo contra ti.'),
('2026-03-04','Miércoles','La ley de Moisés o ceremonial','Hebreos 7:19','Hebreos',7,19,NULL,'Porque nada perfeccionó la ley; mas hízolo la introducción de mejor esperanza, por la cual nos acercamos á Dios.'),
('2026-03-05','Jueves','La ley de Moisés o ceremonial','Efesios 2:15','Efesios',2,15,NULL,'Dirimiendo en su carne las enemistades, la ley de los mandamientos en orden á ritos, para edificar en sí mismo los dos en un nuevo hombre, haciendo la paz,'),
('2026-03-06','Viernes','La ley de Moisés o ceremonial','Colosenses 2:14','Colosenses',2,14,NULL,'Rayendo la cédula de los ritos que nos era contraria, que era contra nosotros, quitándola de en medio y enclavándola en la cruz;'),
('2026-03-07','Sábado','La ley de Moisés o ceremonial','Gálatas 5:1','Gálatas',5,1,NULL,'Estad, pues, firmes en la libertad con que Cristo nos hizo libres, y no volváis otra vez á ser presos en el yugo de servidumbre.'),
('2026-03-08','Domingo','La ley de Moisés o ceremonial','Gálatas 3:10','Gálatas',3,10,NULL,'Porque todos los que son de las obras de la ley, están bajo de maldición. Porque escrito está: Maldito todo aquel que no permaneciere en todas las cosas que están escritas en el libro de la ley, para hacerlas.'),
('2026-03-09','Lunes','La ley de Moisés o ceremonial','Ezequiel 20:25','Ezequiel',20,25,NULL,'Por eso yo también les dí ordenanzas no buenas, y derechos por los cuales no viviesen;'),
('2026-03-10','Martes','La ley de Moisés o ceremonial','Deuteronomio 31:24','Deuteronomio',31,24,NULL,'Y como acabó Moisés de escribir las palabras de esta ley en un libro hasta concluirse,'),
('2026-03-11','Miércoles','La ley de Moisés o ceremonial','Deuteronomio 31:26','Deuteronomio',31,26,NULL,'Tomad este libro de la ley, y ponedlo al lado del arca del pacto de Jehová vuestro Dios, y esté allí por testigo contra ti.'),
('2026-03-12','Jueves','La ley de Moisés o ceremonial','Hebreos 7:16','Hebreos',7,16,NULL,'El cual no es hecho conforme á la ley del mandamiento carnal, sino según la virtud de vida indisoluble;'),
('2026-03-13','Viernes','La ley de Moisés o ceremonial','Hebreos 7:28','Hebreos',7,28,NULL,'Porque la ley constituye sacerdotes á hombres flacos; mas la palabra del juramento, después de la ley, constituye al Hijo, hecho perfecto para siempre.'),
('2026-03-14','Sábado','La ley de Moisés o ceremonial','Hechos 15:5','Hechos',15,5,NULL,'Mas algunos de la secta de los Fariseos, que habían creído, se levantaron, diciendo: Que es menester circuncidarlos, y mandarles que guarden la ley de Moisés.'),
('2026-03-15','Domingo','Profecías cumplidas','Miqueas 5:2','Miqueas',5,2,NULL,'Mas tú, Beth-lehem Ephrata, pequeña para ser en los millares de Judá, de ti me saldrá el que será Señor en Israel; y sus salidas son desde el principio, desde los días del siglo.'),
('2026-03-16','Lunes','Profecías cumplidas','Mateo 2:1','Mateo',2,1,NULL,'Y como fué nacido Jesús en Bethlehem de Judea en días del rey Herodes, he aquí unos magos vinieron del oriente á Jerusalem,'),
('2026-03-17','Martes','Profecías cumplidas','Isaías 7:14','Isaías',7,14,NULL,'Por tanto el mismo Señor os dará señal: He aquí que la virgen concebirá, y parirá hijo, y llamará su nombre Emmanuel.'),
('2026-03-18','Miércoles','Profecías cumplidas','Mateo 1:23','Mateo',1,23,NULL,'He aquí la virgen concebirá y parirá un hijo, y llamarás su nombre Emmanuel, que declarado, es: Con nosotros Dios.'),
('2026-03-19','Jueves','Profecías cumplidas','Oseas 11:1','Oseas',11,1,NULL,'Cuando Israel era muchacho, yo lo amé, y de Egipto llamé á mi hijo.'),
('2026-03-20','Viernes','Profecías cumplidas','Mateo 2:15','Mateo',2,15,NULL,'Y estuvo allá hasta la muerte de Herodes: para que se cumpliese lo que fué dicho por el Señor, por el profeta que dijo: De Egipto llamé á mi Hijo.'),
('2026-03-21','Sábado','Profecías cumplidas','Isaías 53:4','Isaías',53,4,NULL,'Ciertamente llevó él nuestras enfermedades, y sufrió nuestros dolores; y nosotros le tuvimos por azotado, por herido de Dios y abatido.'),
('2026-03-22','Domingo','Profecías cumplidas','Mateo 8:17','Mateo',8,17,NULL,'Para que se cumpliese lo que fué dicho por el profeta Isaías, que dijo: El mismo tomó nuestras enfermedades, y llevó nuestras dolencias.'),
('2026-03-23','Lunes','Profecías cumplidas','Salmos 78:2','Salmos',78,2,NULL,'Abriré mi boca en parábola; hablaré cosas reservadas de antiguo:'),
('2026-03-24','Martes','Profecías cumplidas','Mateo 13:34','Mateo',13,34,NULL,'Todo esto habló Jesús por parábolas á las gentes, y sin parábolas no les hablaba:'),
('2026-03-25','Miércoles','Profecías cumplidas','Isaías 40:11','Isaías',40,11,NULL,'Como pastor apacentará su rebaño; en su brazo cogerá los corderos, y en su seno los llevará; pastoreará suavemente las paridas.'),
('2026-03-26','Jueves','Profecías cumplidas','Juan 10:14','Juan',10,14,NULL,'Yo soy el buen pastor; y conozco mis ovejas, y las mías me conocen.'),
('2026-03-27','Viernes','Profecías cumplidas','Zacarías 11:13','Zacarías',11,13,NULL,'Y díjome Jehová: Echalo al tesorero, hermoso precio con que me han apreciado. Y tomé las treinta piezas de plata, y echélas en la casa de Jehová al tesorero.'),
('2026-03-28','Sábado','Profecías cumplidas','Mateo 27:3','Mateo',27,3,NULL,'Entonces Judas, el que le había entregado, viendo que era condenado, volvió arrepentido las treinta piezas de plata á los príncipes de los sacerdotes y á los ancianos,'),
('2026-03-29','Domingo','Los impedimentos para la oración','Isaías 59:2','Isaías',59,2,NULL,'Mas vuestras iniquidades han hecho división entre vosotros y vuestro Dios, y vuestros pecados han hecho ocultar su rostro de vosotros, para no oir.'),
('2026-03-30','Lunes','Los impedimentos para la oración','Salmos 66:18','Salmos',66,18,NULL,'Si en mi corazón hubiese yo mirado á la iniquidad, el Señor no me oyera.'),
('2026-03-31','Martes','Los impedimentos para la oración','Proverbios 28:9','Proverbios',28,9,NULL,'El que aparta su oído para no oir la ley, su oración también es abominable.'),
